import java.util.*;
import java.util.stream.Collectors;
import java.util.Base64;

public class EventStore {
    private final Set<Long> seenIds = new HashSet<>();
    private final Set<Long> tombstonedIds = new HashSet<>(); // The permanent blacklist
    private final Map<Long, Long> idToTimestamp = new HashMap<>(); // For O(log N) deletion
    private final TreeMap<Long, List<Event>> timeIndex = new TreeMap<>();
    private final List<java.util.function.Consumer<Event>> subscribers = new ArrayList<>();

    public synchronized void append(Event event) {
        // R3 & Tombstone Rule: Reject if seen OR if tombstoned
        if (seenIds.contains(event.id) || tombstonedIds.contains(event.id)) {
            return;
        }

        seenIds.add(event.id);
        idToTimestamp.put(event.id, event.timestamp);
        timeIndex.computeIfAbsent(event.timestamp, k -> new ArrayList<>())
                 .add(event);

        notifySubscribers(event);
    }

    /**
     * Permanent deletion of an ID. 
     * Even if the event arrives later (R2), it will be rejected.
     */
    public synchronized void tombstone(long id) {
        tombstonedIds.add(id);

        // If the event is currently in the store, remove it
        if (idToTimestamp.containsKey(id)) {
            long timestamp = idToTimestamp.remove(id);
            List<Event> eventsAtTime = timeIndex.get(timestamp);
            if (eventsAtTime != null) {
                eventsAtTime.removeIf(e -> e.id == id);
                if (eventsAtTime.isEmpty()) {
                    timeIndex.remove(timestamp);
                }
            }
        }
        // seenIds is kept as-is to ensure R3; tombstonedIds ensures "Never Again"
    }

    public synchronized Map<String, Object> toSnapshot() {
        Map<String, Object> snapshot = new HashMap<>();

        // Serialize active events
        List<Map<String, Object>> events = new ArrayList<>();
        for (List<Event> list : timeIndex.values()) {
            for (Event e : list) {
                events.add(Map.of(
                    "id", Long.toString(e.id), // R1
                    "ts", e.timestamp,
                    "data", Base64.getEncoder().encodeToString(e.data)
                ));
            }
        }

        // Serialize tombstone blacklist
        List<String> tombstones = tombstonedIds.stream()
            .map(Object::toString)
            .collect(Collectors.toList());

        snapshot.put("events", events);
        snapshot.put("tombstones", tombstones);
        return snapshot;
    }

    public synchronized void fromSnapshot(Map<String, Object> snapshot) {
        this.seenIds.clear();
        this.tombstonedIds.clear();
        this.idToTimestamp.clear();
        this.timeIndex.clear();

        // Load tombstones first to ensure re-appended events are rejected
        List<String> tombstones = (List<String>) snapshot.get("tombstones");
        if (tombstones != null) {
            for (String id : tombstones) tombstonedIds.add(Long.parseLong(id));
        }

        List<Map<String, Object>> events = (List<Map<String, Object>>) snapshot.get("events");
        if (events != null) {
            for (Map<String, Object> eMap : events) {
                this.append(new Event(
                    Long.parseLong(eMap.get("id").toString()),
                    ((Number) eMap.get("ts")).longValue(),
                    Base64.getDecoder().decode(eMap.get("data").toString())
                ));
            }
        }
    }

    // ... queryRange, subscribe, and notifySubscribers remain unchanged
}
