import java.util.*;
import java.util.concurrent.CopyOnWriteArrayList;
import java.util.concurrent.locks.ReadWriteLock;
import java.util.concurrent.locks.ReentrantReadWriteLock;
import java.util.function.Consumer;

public class EventStore {

    public static class Event {
        private final long id;          // R1: 64-bit signed integer
        private final long timestamp;   // 64-bit signed timestamp
        private final byte[] payload;

        public Event(long id, long timestamp, byte[] payload) {
            this.id = id;
            this.timestamp = timestamp;
            this.payload = payload;
        }

        public long getId() { return id; }
        public long getTimestamp() { return timestamp; }
        public byte[] getPayload() { return payload; }
    }

    // Handles subscription lifecycle thread-safely
    public interface Subscription {
        void cancel();
    }

    private final ReadWriteLock lock = new ReentrantReadWriteLock();
    private final Set<Long> registeredIds = new HashSet<>();
    private final TreeMap<Long, List<Event>> index = new TreeMap<>();

    // Thread-safe list of active event subscribers
    private final List<Consumer<Event>> subscribers = new CopyOnWriteArrayList<>();

    /**
     * Subscribes a callback to be notified of newly accepted events.
     * Returns a Subscription handle to allow un-subscribing.
     */
    public Subscription subscribe(Consumer<Event> callback) {
        if (callback == null) {
            throw new IllegalArgumentException("Callback cannot be null");
        }
        subscribers.add(callback);
        return () -> subscribers.remove(callback);
    }

    /**
     * Inserts an event into the store.
     * If accepted, notifies all registered subscribers.
     */
    public void insert(Event event) {
        if (event == null) return;

        boolean accepted = false;
        lock.writeLock().lock();
        try {
            // R3: Silently reject duplicate IDs
            if (!registeredIds.contains(event.getId())) {
                registeredIds.add(event.getId());

                // R2: Insert out-of-order into sorted map
                index.computeIfAbsent(event.getTimestamp(), k -> new ArrayList<>()).add(event);
                accepted = true;
            }
        } finally {
            lock.writeLock().unlock();
        }

        // Notify subscribers outside of the database write-lock.
        // This ensures a blocking subscriber doesn't lock the EventStore.
        if (accepted) {
            for (Consumer<Event> subscriber : subscribers) {
                try {
                    subscriber.accept(event);
                } catch (Exception e) {
                    // Safeguard: Prevent a failing subscriber from breaking the ingestion flow.
                    System.err.println("Subscriber threw an exception: " + e.getMessage());
                }
            }
        }
    }

    /**
     * Queries all events whose timestamp falls in the [start, end] range (inclusive).
     */
    public List<Event> queryRange(long start, long end) {
        lock.readLock().lock();
        try {
            List<Event> matchedEvents = new ArrayList<>();
            NavigableMap<Long, List<Event>> subMap = index.subMap(start, true, end, true);
            for (List<Event> events : subMap.values()) {
                matchedEvents.addAll(events);
            }
            return matchedEvents;
        } finally {
            lock.readLock().unlock();
        }
    }
}
```

